import { useEffect, useState } from 'react';
import { loadLabConfig } from '@/services/lab-config.service';
import type { LabRuntimeConfig } from '@/types/lab-config.types';

interface LabConfigState {
  config: LabRuntimeConfig | null;
  error: string | null;
  isLoading: boolean;
}

/**
 * Loads the runtime configuration generated by the gateway bootstrap.
 */
export function useLabConfig(): LabConfigState {
  const [state, setState] = useState<LabConfigState>({
    config: null,
    error: null,
    isLoading: true
  });

  useEffect(() => {
    let isCurrent = true;

    void loadLabConfig()
      .then((config) => {
        if (!isCurrent) {
          return;
        }

        setState({
          config,
          error: null,
          isLoading: false
        });
      })
      .catch((error: unknown) => {
        if (!isCurrent) {
          return;
        }

        setState({
          config: null,
          error: error instanceof Error ? error.message : 'Configurazione runtime non valida.',
          isLoading: false
        });
      });

    return () => {
      isCurrent = false;
    };
  }, []);

  return state;
}
